1932	    /**
1933	     * @ch 依 unshow 的原始/真實押注比值反推 ExtraBet type（即 Mul 索引）
1934	     * @description Mul[type]/Mul[0] === UnshowRealBet/UnshowBaseBet；用交叉相乘（tools.times）避免浮點誤差。
1935	     * 倍率表不足或對不上時保底回 1（Special），維持還原不中斷
1936	     */
1937	    private GetUnshowExtraBetType(): number {
1938	        const FALLBACK_TYPE = 1;
1939	        const baseBet = commonGameManager.UnshowBaseBet;
1940	        const realBet = commonGameManager.UnshowRealBet;
1941	        const mul = this.m_betMultipliers;
1942	
1943	        if ( !mul || mul.length <= 1 || baseBet <= 0 ) {
1944	            error( `[GameView] ExtraBet 還原資料不足 (mul=${mul}, baseBet=${baseBet})，保底用 type=${FALLBACK_TYPE}` );
1945	            return FALLBACK_TYPE;
1946	        }
1947	
1948	        const target = tools.times( realBet, mul[ 0 ] );
1949	        for ( let type = 1; type < mul.length; type++ ) {
1950	            if ( tools.times( baseBet, mul[ type ] ) === target ) {
1951	                return type;
1952	            }
1953	        }
1954	
1955	        error( `[GameView] ExtraBet 倍率對不上 (baseBet=${baseBet}, realBet=${realBet}, mul=${mul})，保底用 type=${FALLBACK_TYPE}` );
1956	        return FALLBACK_TYPE;
1957	    }
