270	    /**
271	     * @ch 事件回調
272	     * @param event 事件名稱
273	     * @param args 事件參數
274	     */
275	    OnEvent(event: string, ...args: any[]) {
276	        switch (event) {
277	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER:
278	                if (this.ValidateSetMultiplierArgs(args)) {
279	                    this.SetMultiplier(args[0] as number, args[1] as number);
280	                }
281	                break;
282	
283	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_WITH_ANIM:
284	                this.SetMultiplierWithAnim(args[0] as number, args[1] as number, args[2] as () => void);
285	                break;
286	                
287	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_LIST:
288	                if (this.ValidateSetMultiplierListArgs(args)) {
289	                    this.SetMultiplierList(args[0] as number[]);
290	                }
291	                break;
292	
293	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW:
294	                if (this.ValidateSetShowArgs(args)) {
295	                    this.SetShow(args[0] as number, args[1] as boolean);
296	                }
297	                break;
298	
299	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_FRAME_SHOW:
300	                if (this.ValidateSetFrameShowArgs(args)) {
301	                    this.SetFrameShow(args[0] as number, args[1] as boolean);
302	                }
303	                break;
304	            case MULTIPLIER_BASE_MANAGER_EVENT.POP_MULITEM:
305	                if (this.ValidatePopMulItemArgs(args)) {
306	                    this.PopMulItem(args[0] as number, args[1] as Node);
307	                }
308	                break;
309	            case MULTIPLIER_BASE_MANAGER_EVENT.PUSH_MULITEM:
310	                if (this.ValidatePushMulItemArgs(args)) {
311	                    this.PushMulItem(args[0] as number);
312	                }
313	                break;
314	            case MULTIPLIER_BASE_MANAGER_EVENT.MULITEM_FLY_TO_TARGET:
315	                if (this.ValidateMulItemFlyToTargetArgs(args)) {
316	                    this.MulItemFlyToTarget(args[0] as number, args[1] as Vec3, args[2] as number, args[3] as () => void);
317	                }
318	                break;
319	            case MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER:
320	                if (this.ValidateAddMultiplierArgs(args)) {
321	                    this.AddMultiplier(args[0] as number);
322	                }
323	                break;
324	            case MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER_WITH_ANIM:
325	                if (this.ValidateAddMultiplierArgs(args)) {
326	                    this.AddMultiplierWithAnim(args[0] as number, args[1] as number, args[2] as () => void);
327	                }
328	                break;
329	            case MULTIPLIER_BASE_MANAGER_EVENT.CHECK_MULTIPLIER_WITH_SERVER:
330	                this.CheckMultiplierWithServer(
331	                    args[0] as protocol.ar2pq9Proto.IIntAry[],
332	                    args[1] as number[]
333	                );
334	                break;
335	            default:
336	                warn('[MultiplierBaseManager] OnEvent: 未知的事件', event);
337	        }
338	    }
