541	    /**
542	     * @ch 指定索引的倍率加 1（index 為負數時設置全部）
543	     * 已達最大倍數時保持最高倍數不變
544	     * @param index 目標 MultiplierBase 索引，負數表示全部
545	     */
546	    private AddMultiplier(index: number): void {
547	        if (index < 0) {
548	            this.AddAllMultiplier();
549	            return;
550	        }
551	        const item = this.GetMultiplierBase(index);
552	        if (!item) return;
553	        if (this.IsAtMaxMultiplier(item)) {
554	            item.SetMultiplier(item.GetMaxMultiplierIndex());
555	            return;
556	        }
557	        item.SetMultiplier(item.GetMultiplierIndex() + 1);
558	    }
