560	    /**
561	     * @ch 所有 MultiplierBase 的倍率加 1
562	     * 已達最大倍數時保持最高倍數不變
563	     */
564	    private AddAllMultiplier(): void {
565	        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
566	            warn('[MultiplierBaseManager] AddAllMultiplier: MultiplierBase 陣列未設置');
567	            return;
568	        }
569	        this.m_multiplierBases.forEach((item, i) => {
570	            if (!item) {
571	                warn(`[MultiplierBaseManager] AddAllMultiplier: 索引 ${i} 的 MultiplierBase 未設置`);
572	                return;
573	            }
574	            if (this.IsAtMaxMultiplier(item)) {
575	                item.SetMultiplier(item.GetMaxMultiplierIndex());
576	                return;
577	            }
578	            item.SetMultiplier(item.GetMultiplierIndex() + 1);
579	        });
580	    }
581	
582	    /**
583	     * @ch 播放加成動畫後指定索引的倍率加 amount 階（index 為負數時設置全部）
584	     * 已達最大倍數時仍播放升級動畫，倍數保持最高
585	     * @param index 目標 MultiplierBase 索引，負數表示全部
586	     * @param amount 一次加幾階（標靶∩標靶重疊位置 > 1；預設 1，非正數一律視為 1）
587	     * @param callback 動畫完成後的回調函數
588	     */
589	    private AddMultiplierWithAnim(index: number, amount: number = 1, callback?: () => void): void {
590	        const step = (typeof amount === 'number' && amount > 0) ? Math.floor(amount) : 1;
591	        if (index < 0) {
592	            this.AddAllMultiplierWithAnim(step, callback);
593	            return;
594	        }
595	        const item = this.GetMultiplierBase(index);
596	        if (!item) { if (callback) callback(); return; }
597	        // 已達最大倍數時仍播升級動畫，保持在最高倍數
598	        const target = Math.min(item.GetMultiplierIndex() + step, item.GetMaxMultiplierIndex());
599	        item.PlayUpgradeAndSetMultiplier(target).then(() => {
600	            if (callback) callback();
601	        });
602	    }
603	
604	    /**
605	     * @ch 播放加成動畫後所有 MultiplierBase 的倍率加 step 階
606	     * 已達最大倍數時仍播放升級動畫，倍數保持最高
607	     * @param step 一次加幾階（預設 1）
608	     * @param callback 全部動畫完成後的回調函數
609	     */
610	    private AddAllMultiplierWithAnim(step: number = 1, callback?: () => void): void {
611	        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
612	            warn('[MultiplierBaseManager] AddAllMultiplierWithAnim: MultiplierBase 陣列未設置');
613	            if (callback) callback();
614	            return;
615	        }
616	        const promises: Promise<void>[] = [];
617	        this.m_multiplierBases.forEach((item, i) => {
618	            if (!item) {
619	                warn(`[MultiplierBaseManager] AddAllMultiplierWithAnim: 索引 ${i} 的 MultiplierBase 未設置`);
620	                return;
621	            }
622	            // 已達最大倍數時仍播升級動畫，保持在最高倍數
623	            const target = Math.min(item.GetMultiplierIndex() + step, item.GetMaxMultiplierIndex());
624	            promises.push(item.PlayUpgradeAndSetMultiplier(target));
625	        });
626	        Promise.all(promises).then(() => {
627	            if (callback) callback();
628	        });
629	    }
