631	    /**
632	     * @ch 回歸守衛：驗證被消除位置的乘倍底板當前 index 是否等於 Server 期望（BasePlateIndex）
633	     * 位置 index = col*ROW+row 對應 m_multiplierBases。Server 值會先夾到顯示上限再比對，
634	     * 避免高倍率被 clamp（SetMultiplier 內）造成假警報。不一致只 error log，不影響玩法
635	     * （同 SlotReels.CheckPlateInfo 風格）。
636	     * @param basePlateIndex Server 每位置底板絕對 index（[col].Data[row]）
637	     * @param positions 本盤被消除的位置（一維索引）
638	     */
639	    private CheckMultiplierWithServer(
640	        basePlateIndex: protocol.ar2pq9Proto.IIntAry[],
641	        positions: number[]
642	    ): void {
643	        if (!basePlateIndex || basePlateIndex.length === 0) return;
644	        if (!positions || positions.length === 0) return;
645	
646	        const errors: any[] = [];
647	        for (const pos of positions) {
648	            if (pos < 0 || pos >= this.m_multiplierBases.length) continue;
649	            const item = this.m_multiplierBases[pos];
650	            if (!item) continue;
651	
652	            const col = Math.floor(pos / Game_Define.ROW);
653	            const row = pos % Game_Define.ROW;
654	            const expected = basePlateIndex[col]?.Data?.[row];
655	            if (expected === null || expected === undefined) continue;
656	
657	            // Server 值夾到顯示上限再比（顯示本就 clamp，超限非錯誤）
658	            const expectedClamped = Math.min(expected, item.GetMaxMultiplierIndex());
659	            const actual = item.GetMultiplierIndex();
660	            if (actual !== expectedClamped) {
661	                errors.push({ pos, col, row, expected, expectedClamped, actual });
662	            }
663	        }
664	
665	        if (errors.length > 0) {
666	            error('[MultiplierBaseManager] 乘倍底板與 Server 期望值不一致:', JSON.stringify(errors));
667	        }
668	    }
669	    //#endregion Methods
670	
671	    //#region 測試功能
672	    /**
673	     * @ch 測試按鍵處理
674	     * - 數字鍵 1：設置索引 0 的倍率為 3
675	     * - 數字鍵 2：設置索引 0 的倍率為 6
676	     * - 數字鍵 3：設置所有倍率為 5
677	     * - 數字鍵 4：隱藏索引 0
678	     * - 數字鍵 5：顯示索引 0
679	     * - 數字鍵 6：批次設置倍率 [2, 5, 8]
680	     */
681	    private CheckTestKeyCode(event: EventKeyboard): void {
682	        switch (event.keyCode) {
683	            case KeyCode.DIGIT_1:
684	
685	                this.SetMultiplier(0, 3);
686	                break;
687	
688	            case KeyCode.DIGIT_2:
689	
690	                this.SetMultiplier(0, 6);
691	                break;
692	
693	            case KeyCode.DIGIT_3:
694	
695	                this.SetMultiplier(-1, 5);
696	                break;
697	
698	            case KeyCode.DIGIT_4:
699	
700	                this.SetShow(0, false);
701	                break;
702	
703	            case KeyCode.DIGIT_5:
704	
705	                this.SetShow(0, true);
706	                break;
707	
708	            case KeyCode.DIGIT_6:
709	
710	                this.SetMultiplierList([2, 5, 8]);
711	                break;
712	        }
713	    }
714	    //#endregion 測試功能
715	}
