import { _decorator, Component, EventKeyboard, Input, input, KeyCode, log, warn, error, Node, Vec3, UIOpacity, tween } from 'cc';
import { DEBUG } from 'cc/env';
import { eventManager } from 'db://astarte-framework/Managers';
import { MultiplierBase } from './MultiplierBase';
import Game_Define from '../Game_Define';
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
const { ccclass, property } = _decorator;

/**@ch MultiplierBase 管理器事件*/
export const MULTIPLIER_BASE_MANAGER_EVENT = {
    /**
     * @ch 設置指定索引的倍率（index 為負數時設置全部）
     * @param index number 目標 MultiplierBase 索引，負數表示全部
     * @param multiplierIndex number 倍率索引
     */
    SET_MULTIPLIER: "MULTIPLIER_BASE_MANAGER_SET_MULTIPLIER",

    /**
     * @ch 播放升級動畫後設置倍率
     * @param index number 目標 MultiplierBase 索引
     * @param multiplierIndex number 倍率索引
     * @param callback function 完成回調
     */
    SET_MULTIPLIER_WITH_ANIM: "MULTIPLIER_BASE_MANAGER_SET_MULTIPLIER_WITH_ANIM",

    /**
     * @ch 批次設置多個 MultiplierBase 的倍率
     * @param multiplierIndexList number[] 倍率索引陣列，陣列位置對應 MultiplierBase 索引
     */
    SET_MULTIPLIER_LIST: "MULTIPLIER_BASE_MANAGER_SET_MULTIPLIER_LIST",

    /**
     * @ch 設置指定索引的 MultiplierBase 顯示狀態（index 為負數時設置全部）
     * @param index number 目標 MultiplierBase 索引，負數表示全部
     * @param isShow boolean 是否顯示
     */
    SET_SHOW: "MULTIPLIER_BASE_MANAGER_SET_SHOW",

    /**
     * @ch 設置指定索引的 MultiplierBase 底框顯示狀態（index 為負數時設置全部）
     * @param index number 目標 MultiplierBase 索引，負數表示全部
     * @param isShow boolean 是否顯示
     */
    SET_FRAME_SHOW: "MULTIPLIER_BASE_MANAGER_SET_FRAME_SHOW",

    /**
     * @ch 彈出 乘倍物件到指定層級
     * @param index number 目標 MultiplierBase 索引
     * @param node Node 要彈出的節點
     */
    POP_MULITEM: "MULTIPLIER_BASE_MANAGER_POP_MULITEM",

    /**
     * @ch 復原 乘倍物件到原來位置
     * @param index number 目標 MultiplierBase 索引
     */
    PUSH_MULITEM: "MULTIPLIER_BASE_MANAGER_PUSH_MULITEM",

    /**
     * @ch 乘倍物件飛至贏分位置
     * @param index number 目標 MultiplierBase 索引
     * @param targetPos Vec3 要飛至的位置
     * @param duration number 動畫持續時間（秒）
     * @param callback function 動畫完成後的回調函數
     */
    MULITEM_FLY_TO_TARGET: "MULTIPLIER_BASE_MANAGER_MULITEM_FLY_TO_TARGET",

    /**
     * @ch 指定索引的倍率加1（index 為負數時設置全部）
     * @param index number 目標 MultiplierBase 索引，負數表示全部
     */
    ADD_MULTIPLIER: "MULTIPLIER_BASE_MANAGER_ADD_MULTIPLIER",

    /**
     * @ch 播放加成動畫後指定索引的倍率加 amount 階（index 為負數時設置全部）
     * @param index number 目標 MultiplierBase 索引，負數表示全部
     * @param amount number 一次加幾階（標靶∩標靶重疊位置 > 1；可省略，預設 1）
     * @param callback function 動畫完成後的回調函數
     */
    ADD_MULTIPLIER_WITH_ANIM: "MULTIPLIER_BASE_MANAGER_ADD_MULTIPLIER_WITH_ANIM",

    /**
     * @ch 回歸守衛：驗證被消除位置的乘倍底板當前 index 是否等於 Server 期望值
     * @param basePlateIndex protocol.ar2pq9Proto.IIntAry[] Server 每位置底板絕對 index（[col].Data[row]）
     * @param positions number[] 本盤被消除的位置（一維索引）
     */
    CHECK_MULTIPLIER_WITH_SERVER: "MULTIPLIER_BASE_MANAGER_CHECK_MULTIPLIER_WITH_SERVER",
}

/**@ch MultiplierBase 管理器*/
@ccclass('MultiplierBaseManager')
export class MultiplierBaseManager extends Component {
    //#region Constants
    /**@ch 需要註冊的事件列表*/
    private static readonly EVENTS_TO_REGISTER = [
        MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER,
        MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_WITH_ANIM,
        MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_LIST,
        MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW,
        MULTIPLIER_BASE_MANAGER_EVENT.SET_FRAME_SHOW,
        MULTIPLIER_BASE_MANAGER_EVENT.POP_MULITEM,
        MULTIPLIER_BASE_MANAGER_EVENT.PUSH_MULITEM,
        MULTIPLIER_BASE_MANAGER_EVENT.MULITEM_FLY_TO_TARGET,
        MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER,
        MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER_WITH_ANIM,
        MULTIPLIER_BASE_MANAGER_EVENT.CHECK_MULTIPLIER_WITH_SERVER,
    ];
    //#endregion Constants

    //#region Properties
    @property({
        type: [MultiplierBase],
        tooltip: "MultiplierBase 元件陣列"
    })
    private m_multiplierBases: MultiplierBase[] = [];
    //#endregion Properties

    //#region Variables
    /**@ch 是否已初始化*/
    private m_isInitialized: boolean = false;
    //#endregion Variables

    //#region Lifecycle
    /**@ch 元件載入時調用*/
    onLoad() {
        this.RegisterEvent();
        this.RegisterKeyboardEvents();
    }

    /**@ch 元件銷毀時調用*/
    onDestroy() {
        if (!this.m_isInitialized) return;
        this.UnregisterEvent();
        this.UnregisterKeyboardEvents();
        this.m_isInitialized = false;
    }
    //#endregion Lifecycle

    //#region Event Management
    /**@ch 註冊鍵盤事件（測試用）*/
    private RegisterKeyboardEvents(): void {
        if (!DEBUG) return;
        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**@ch 取消註冊鍵盤事件（測試用）*/
    private UnregisterKeyboardEvents(): void {
        if (!DEBUG) return;
        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**@ch 註冊事件*/
    private RegisterEvent(): void {
        MultiplierBaseManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });
        this.m_isInitialized = true;
    }

    /**@ch 取消註冊事件*/
    private UnregisterEvent(): void {
        MultiplierBaseManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });
    }

    /**
     * @ch 驗證 SET_MULTIPLIER 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateSetMultiplierArgs(args: any[]): boolean {
        if (typeof args[0] !== 'number' || typeof args[1] !== 'number') {
            warn('[MultiplierBaseManager] SET_MULTIPLIER: 無效的參數', args[0], args[1]);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 SET_MULTIPLIER_LIST 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateSetMultiplierListArgs(args: any[]): boolean {
        if (!Array.isArray(args[0]) || args[0].length === 0) {
            warn('[MultiplierBaseManager] SET_MULTIPLIER_LIST: 無效的參數', args[0]);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 SET_SHOW 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateSetShowArgs(args: any[]): boolean {
        if (typeof args[0] !== 'number' || typeof args[1] !== 'boolean') {
            warn('[MultiplierBaseManager] SET_SHOW: 無效的參數', args[0], args[1]);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 SET_FRAME_SHOW 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateSetFrameShowArgs(args: any[]): boolean {
        if (typeof args[0] !== 'number' || typeof args[1] !== 'boolean') {
            warn('[MultiplierBaseManager] SET_FRAME_SHOW: 無效的參數', args[0], args[1]);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 POP_MULITEM 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidatePopMulItemArgs(args: any[]): boolean {
        if (typeof args[0] !== 'number' ) {
            warn('[MultiplierBaseManager] POP_MULITEM: 無效的參數', args[0], args[1]);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 PUSH_MULITEM 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidatePushMulItemArgs(args: any[]): boolean {
        if (typeof args[0] !== 'number' ) {
            warn('[MultiplierBaseManager] PUSH_MULITEM: 無效的參數', args[0], args[1]);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 MULITEM_FLY_TO_TARGET 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateMulItemFlyToTargetArgs(args: any[]): boolean {
        if (typeof args[0] !== 'number' || typeof args[2] !== 'number' || typeof args[3] !== 'function') {
            warn('[MultiplierBaseManager] MULITEM_FLY_TO_TARGET: 無效的參數', args[0], args[1]);
            return false;
        }
        return true;
    }
    /**
     * @ch 驗證 ADD_MULTIPLIER 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateAddMultiplierArgs(args: any[]): boolean {
        if (typeof args[0] !== 'number') {
            warn('[MultiplierBaseManager] ADD_MULTIPLIER: 無效的參數', args[0]);
            return false;
        }
        return true;
    }

    /**
     * @ch 事件回調
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent(event: string, ...args: any[]) {
        switch (event) {
            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER:
                if (this.ValidateSetMultiplierArgs(args)) {
                    this.SetMultiplier(args[0] as number, args[1] as number);
                }
                break;

            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_WITH_ANIM:
                this.SetMultiplierWithAnim(args[0] as number, args[1] as number, args[2] as () => void);
                break;

            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_LIST:
                if (this.ValidateSetMultiplierListArgs(args)) {
                    this.SetMultiplierList(args[0] as number[]);
                }
                break;

            case MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW:
                if (this.ValidateSetShowArgs(args)) {
                    this.SetShow(args[0] as number, args[1] as boolean);
                }
                break;

            case MULTIPLIER_BASE_MANAGER_EVENT.SET_FRAME_SHOW:
                if (this.ValidateSetFrameShowArgs(args)) {
                    this.SetFrameShow(args[0] as number, args[1] as boolean);
                }
                break;
            case MULTIPLIER_BASE_MANAGER_EVENT.POP_MULITEM:
                if (this.ValidatePopMulItemArgs(args)) {
                    this.PopMulItem(args[0] as number, args[1] as Node);
                }
                break;
            case MULTIPLIER_BASE_MANAGER_EVENT.PUSH_MULITEM:
                if (this.ValidatePushMulItemArgs(args)) {
                    this.PushMulItem(args[0] as number);
                }
                break;
            case MULTIPLIER_BASE_MANAGER_EVENT.MULITEM_FLY_TO_TARGET:
                if (this.ValidateMulItemFlyToTargetArgs(args)) {
                    this.MulItemFlyToTarget(args[0] as number, args[1] as Vec3, args[2] as number, args[3] as () => void);
                }
                break;
            case MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER:
                if (this.ValidateAddMultiplierArgs(args)) {
                    this.AddMultiplier(args[0] as number);
                }
                break;
            case MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER_WITH_ANIM:
                if (this.ValidateAddMultiplierArgs(args)) {
                    this.AddMultiplierWithAnim(args[0] as number, args[1] as number, args[2] as () => void);
                }
                break;
            case MULTIPLIER_BASE_MANAGER_EVENT.CHECK_MULTIPLIER_WITH_SERVER:
                this.CheckMultiplierWithServer(
                    args[0] as protocol.ar2pq9Proto.IIntAry[],
                    args[1] as number[]
                );
                break;
            default:
                warn('[MultiplierBaseManager] OnEvent: 未知的事件', event);
        }
    }
    //#endregion Event Management

    //#region Methods
    /**
     * @ch 設置指定索引的倍率（index 為負數時設置全部）
     * @param index 目標 MultiplierBase 索引，負數表示全部
     * @param multiplierIndex 倍率索引
     */
    private SetMultiplier(index: number, multiplierIndex: number): void {
        if (index < 0) {
            this.SetAllMultiplier(multiplierIndex);
            return;
        }
        const item = this.GetMultiplierBase(index);
        if (!item) return;
        item.SetMultiplier(multiplierIndex);
    }

    /**
     * @ch 播放升級動畫後設置倍率
     */
    private SetMultiplierWithAnim(index: number, multiplierIndex: number, callback?: () => void): void {
        if (typeof index !== 'number' || typeof multiplierIndex !== 'number') {
            if (callback) callback();
            return;
        }
        const item = this.GetMultiplierBase(index);
        if (!item) { if (callback) callback(); return; }
        item.PlayUpgradeAndSetMultiplier(multiplierIndex).then(() => {
            if (callback) callback();
        });
    }

    /**
     * @ch 設置所有 MultiplierBase 的倍率
     * @param multiplierIndex 倍率索引
     */
    private SetAllMultiplier(multiplierIndex: number): void {
        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
            warn('[MultiplierBaseManager] SetAllMultiplier: MultiplierBase 陣列未設置');
            return;
        }
        this.m_multiplierBases.forEach((item, i) => {
            if (!item) {
                warn(`[MultiplierBaseManager] SetAllMultiplier: 索引 ${i} 的 MultiplierBase 未設置`);
                return;
            }
            item.SetMultiplier(multiplierIndex);
        });
    }

    /**
     * @ch 設置指定索引的 MultiplierBase 顯示狀態（index 為負數時設置全部）
     * @param index 目標 MultiplierBase 索引，負數表示全部
     * @param isShow 是否顯示
     */
    private SetShow(index: number, isShow: boolean): void {
        if (index < 0) {
            this.SetAllShow(isShow);
            return;
        }
        const item = this.GetMultiplierBase(index);
        if (!item) return;
        item.node.active = isShow;
    }

    /**
     * @ch 設置所有 MultiplierBase 的顯示狀態
     * @param isShow 是否顯示
     */
    private SetAllShow(isShow: boolean): void {
        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
            warn('[MultiplierBaseManager] SetAllShow: MultiplierBase 陣列未設置');
            return;
        }
        this.m_multiplierBases.forEach((item, i) => {
            if (!item) {
                warn(`[MultiplierBaseManager] SetAllShow: 索引 ${i} 的 MultiplierBase 未設置`);
                return;
            }
            if (isShow) {
                item.node.active = true;
                let opacity = item.node.getComponent(UIOpacity);
                if (!opacity) { opacity = item.node.addComponent(UIOpacity); }
                opacity.opacity = 0;
                tween(opacity).to(0.3, { opacity: 255 }).start();
            } else {
                item.node.active = false;
            }
        });
    }

    /**
     * @ch 設置指定索引的 MultiplierBase 底框顯示狀態（index 為負數時設置全部）
     * @param index 目標 MultiplierBase 索引，負數表示全部
     * @param isShow 是否顯示
     */
    private SetFrameShow(index: number, isShow: boolean): void {
        if (index < 0) {
            this.SetAllFrameShow(isShow);
            return;
        }
        const item = this.GetMultiplierBase(index);
        if (!item) return;
        item.SetFrameShow(isShow);
    }

    /**
     * @ch 設置所有 MultiplierBase 的底框顯示狀態
     * @param isShow 是否顯示
     */
    private SetAllFrameShow(isShow: boolean): void {
        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
            warn('[MultiplierBaseManager] SetAllFrameShow: MultiplierBase 陣列未設置');
            return;
        }
        this.m_multiplierBases.forEach((item, i) => {
            if (!item) {
                warn(`[MultiplierBaseManager] SetAllFrameShow: 索引 ${i} 的 MultiplierBase 未設置`);
                return;
            }
            item.SetFrameShow(isShow);
        });
    }

    /**
     * @ch 批次設置多個 MultiplierBase 的倍率
     * @param multiplierIndexList 倍率索引陣列，陣列位置對應 MultiplierBase 索引
     */
    private SetMultiplierList(multiplierIndexList: number[]): void {
        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
            warn('[MultiplierBaseManager] SetMultiplierList: MultiplierBase 陣列未設置');
            return;
        }
        if (multiplierIndexList.length > this.m_multiplierBases.length) {
            warn('[MultiplierBaseManager] SetMultiplierList: 資料數量超過 MultiplierBase 數量',
                multiplierIndexList.length, '>', this.m_multiplierBases.length);
        }
        const count = Math.min(multiplierIndexList.length, this.m_multiplierBases.length);
        for (let i = 0; i < count; i++) {
            const item = this.m_multiplierBases[i];
            if (!item) {
                warn(`[MultiplierBaseManager] SetMultiplierList: 索引 ${i} 的 MultiplierBase 未設置`);
                continue;
            }
            item.SetMultiplier(multiplierIndexList[i]);
        }
    }

    /**
     * @ch 取得指定索引的 MultiplierBase（含邊界檢查）
     * @param index 索引
     * @returns MultiplierBase 或 null
     */
    private GetMultiplierBase(index: number): MultiplierBase | null {
        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
            warn('[MultiplierBaseManager] GetMultiplierBase: MultiplierBase 陣列未設置');
            return null;
        }
        if (index < 0 || index >= this.m_multiplierBases.length) {
            warn(`[MultiplierBaseManager] GetMultiplierBase: 索引 ${index} 超出範圍 (0~${this.m_multiplierBases.length - 1})`);
            return null;
        }
        const item = this.m_multiplierBases[index];
        if (!item) {
            warn(`[MultiplierBaseManager] GetMultiplierBase: 索引 ${index} 的 MultiplierBase 未設置`);
            return null;
        }
        return item;
    }

    /**
     * @ch 彈出 乘倍物件到指定層級
     * @param index 目標 MultiplierBase 索引
     */
    private PopMulItem(index: number, parent: Node): void {
        const item = this.GetMultiplierBase(index);
        if (!item) return;
        item.SetMultiplierNodeToOtherLayer(parent);
    }

    private PushMulItem(index: number): void {
        const item = this.GetMultiplierBase(index);
        if (!item) return;
        item.RecoverMultiplierNode();
    }

    private MulItemFlyToTarget(index: number, targetPos: Vec3, duration: number, callback: () => void): void {
        const item = this.GetMultiplierBase(index);
        if (!item) return;
        item.MulItemFlyToTarget(targetPos, duration, callback);
    }

    /**
     * @ch 判斷指定 MultiplierBase 是否已達倍率上限
     * @param item 目標 MultiplierBase
     * @returns 已達上限為 true
     */
    private IsAtMaxMultiplier(item: MultiplierBase): boolean {
        return item.GetMultiplierIndex() >= item.GetMaxMultiplierIndex();
    }

    /**
     * @ch 指定索引的倍率加 1（index 為負數時設置全部）
     * 已達最大倍數時保持最高倍數不變
     * @param index 目標 MultiplierBase 索引，負數表示全部
     */
    private AddMultiplier(index: number): void {
        if (index < 0) {
            this.AddAllMultiplier();
            return;
        }
        const item = this.GetMultiplierBase(index);
        if (!item) return;
        if (this.IsAtMaxMultiplier(item)) {
            item.SetMultiplier(item.GetMaxMultiplierIndex());
            return;
        }
        item.SetMultiplier(item.GetMultiplierIndex() + 1);
    }

    /**
     * @ch 所有 MultiplierBase 的倍率加 1
     * 已達最大倍數時保持最高倍數不變
     */
    private AddAllMultiplier(): void {
        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
            warn('[MultiplierBaseManager] AddAllMultiplier: MultiplierBase 陣列未設置');
            return;
        }
        this.m_multiplierBases.forEach((item, i) => {
            if (!item) {
                warn(`[MultiplierBaseManager] AddAllMultiplier: 索引 ${i} 的 MultiplierBase 未設置`);
                return;
            }
            if (this.IsAtMaxMultiplier(item)) {
                item.SetMultiplier(item.GetMaxMultiplierIndex());
                return;
            }
            item.SetMultiplier(item.GetMultiplierIndex() + 1);
        });
    }

    /**
     * @ch 播放加成動畫後指定索引的倍率加 amount 階（index 為負數時設置全部）
     * 已達最大倍數時仍播放升級動畫，倍數保持最高
     * @param index 目標 MultiplierBase 索引，負數表示全部
     * @param amount 一次加幾階（標靶∩標靶重疊位置 > 1；預設 1，非正數一律視為 1）
     * @param callback 動畫完成後的回調函數
     */
    private AddMultiplierWithAnim(index: number, amount: number = 1, callback?: () => void): void {
        const step = (typeof amount === 'number' && amount > 0) ? Math.floor(amount) : 1;
        if (index < 0) {
            this.AddAllMultiplierWithAnim(step, callback);
            return;
        }
        const item = this.GetMultiplierBase(index);
        if (!item) { if (callback) callback(); return; }
        // 已達最大倍數時仍播升級動畫，保持在最高倍數
        const target = Math.min(item.GetMultiplierIndex() + step, item.GetMaxMultiplierIndex());
        item.PlayUpgradeAndSetMultiplier(target).then(() => {
            if (callback) callback();
        });
    }

    /**
     * @ch 播放加成動畫後所有 MultiplierBase 的倍率加 step 階
     * 已達最大倍數時仍播放升級動畫，倍數保持最高
     * @param step 一次加幾階（預設 1）
     * @param callback 全部動畫完成後的回調函數
     */
    private AddAllMultiplierWithAnim(step: number = 1, callback?: () => void): void {
        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
            warn('[MultiplierBaseManager] AddAllMultiplierWithAnim: MultiplierBase 陣列未設置');
            if (callback) callback();
            return;
        }
        const promises: Promise<void>[] = [];
        this.m_multiplierBases.forEach((item, i) => {
            if (!item) {
                warn(`[MultiplierBaseManager] AddAllMultiplierWithAnim: 索引 ${i} 的 MultiplierBase 未設置`);
                return;
            }
            // 已達最大倍數時仍播升級動畫，保持在最高倍數
            const target = Math.min(item.GetMultiplierIndex() + step, item.GetMaxMultiplierIndex());
            promises.push(item.PlayUpgradeAndSetMultiplier(target));
        });
        Promise.all(promises).then(() => {
            if (callback) callback();
        });
    }

    /**
     * @ch 回歸守衛：驗證被消除位置的乘倍底板當前 index 是否等於 Server 期望（BasePlateIndex）
     * 位置 index = col*ROW+row 對應 m_multiplierBases。Server 值會先夾到顯示上限再比對，
     * 避免高倍率被 clamp（SetMultiplier 內）造成假警報。不一致只 error log，不影響玩法
     * （同 SlotReels.CheckPlateInfo 風格）。
     * @param basePlateIndex Server 每位置底板絕對 index（[col].Data[row]）
     * @param positions 本盤被消除的位置（一維索引）
     */
    private CheckMultiplierWithServer(
        basePlateIndex: protocol.ar2pq9Proto.IIntAry[],
        positions: number[]
    ): void {
        if (!basePlateIndex || basePlateIndex.length === 0) return;
        if (!positions || positions.length === 0) return;

        const errors: any[] = [];
        for (const pos of positions) {
            if (pos < 0 || pos >= this.m_multiplierBases.length) continue;
            const item = this.m_multiplierBases[pos];
            if (!item) continue;

            const col = Math.floor(pos / Game_Define.ROW);
            const row = pos % Game_Define.ROW;
            const expected = basePlateIndex[col]?.Data?.[row];
            if (expected === null || expected === undefined) continue;

            // Server 值夾到顯示上限再比（顯示本就 clamp，超限非錯誤）
            const expectedClamped = Math.min(expected, item.GetMaxMultiplierIndex());
            const actual = item.GetMultiplierIndex();
            if (actual !== expectedClamped) {
                errors.push({ pos, col, row, expected, expectedClamped, actual });
            }
        }

        if (errors.length > 0) {
            error('[MultiplierBaseManager] 乘倍底板與 Server 期望值不一致:', JSON.stringify(errors));
        }
    }
    //#endregion Methods

    //#region 測試功能
    /**
     * @ch 測試按鍵處理
     * - 數字鍵 1：設置索引 0 的倍率為 3
     * - 數字鍵 2：設置索引 0 的倍率為 6
     * - 數字鍵 3：設置所有倍率為 5
     * - 數字鍵 4：隱藏索引 0
     * - 數字鍵 5：顯示索引 0
     * - 數字鍵 6：批次設置倍率 [2, 5, 8]
     */
    private CheckTestKeyCode(event: EventKeyboard): void {
        switch (event.keyCode) {
            case KeyCode.DIGIT_1:

                this.SetMultiplier(0, 3);
                break;

            case KeyCode.DIGIT_2:

                this.SetMultiplier(0, 6);
                break;

            case KeyCode.DIGIT_3:

                this.SetMultiplier(-1, 5);
                break;

            case KeyCode.DIGIT_4:

                this.SetShow(0, false);
                break;

            case KeyCode.DIGIT_5:

                this.SetShow(0, true);
                break;

            case KeyCode.DIGIT_6:

                this.SetMultiplierList([2, 5, 8]);
                break;
        }
    }
    //#endregion 測試功能
}

