import { log } from "cc";
import { newBottombarManager, BaseState, commonGameManager, SlotBottomBarState, stateManager, eventManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { roundController } from "db://astarte-framework/utilis";
import { FREE_GAME_UI_MANAGER_EVENT } from "../FreeGame/FreeGameUIManager";
import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";

export class SpinState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter() {

        log( "OnEnter State : SPIN" );
        this.m_gameView.CurPlateIndex = 0;


        roundController.StartSpin();
        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
        this.m_gameView.ClearAll();

        if (commonGameManager.HasUnshow) {
            commonGameManager.HasUnshow = false;
            this.m_gameView.IsHardStop = newBottombarManager.IsHardStop;
            this.m_gameView.StartSpin();
            this.m_gameView.OnRecvSpinAck(this.m_gameView.UnshowSpinAck, true);
            this.m_gameView.UnshowSpinAck = null;
        }
        else {
            this.m_gameView.CurRoundIndex = this.m_gameView.CurRoundIndex + 1;
            this.m_gameView.StartSpin();
        }

        if (this.m_gameView.IsFreeGame) {
            const thisRoundInfo = this.m_gameView.SpinAck.RoundQueue[this.m_gameView.CurRoundIndex];
            this.m_gameView.SetNowRoundInfo(thisRoundInfo);
            eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND, 
                thisRoundInfo.FeverNowRound, this.m_gameView.FreeTotalRound);
            await this.m_gameView.ShowBigAwardHint( this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ] );


            if (this.m_gameView.IsHardStop) {
                this.m_gameView.SlotReels.ClickStopBtn();
                newBottombarManager.SetSpinWithSpeed();
            }
            else {
                if (!newBottombarManager.IsAutoSpin) {
                    newBottombarManager.SetSpinState(SlotBottomBarState.START_SPIN);
                }
            }
        }
        else
        {
            this.m_gameView.RoundWin = 0;
            eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER, -1,0 );
            eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.SET_FRAME_SHOW, -1,false);
            eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1,false);
        }
    }

    public OnProcess( dt: number )
    {
        this.m_gameView.SlotReels.Spin(dt);
        if (!this.m_gameView.SlotReels.IsStop) {
            return;
        }

        this.m_gameView.CanPlateStop = true;
        this.m_gameView.CanSpaceStop = true;
        if (!newBottombarManager.IsAutoSpin) {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_SPIN);
        }

        //stateManager.NextState( Game_Define.GameState.EXPLODE );

        stateManager.NextState(Game_Define.GameState.COUNT_MULT);
    }

    public OnLeave()
    {

    }
}

